#include <bits/stdc++.h>
using namespace std;

int t,en=549855;
char s[5][5];
int d[8][2]={{2,1},{2,-1},{-2,1},{-2,-1},{1,2},{1,-2},{-1,2},{-1,-2}};

int f(int b,int ex,int ey){
    int res=0;
    for(int i=0;i<25;i++)
        if((((b>>i)&1)!=((en>>i)&1) || i==12 && (ex!=2 || ey!=2)) && (ex!=i/5 || ey!=i%5))
            res++;
    return res;
}

void output(int b,int ex,int ey){
	puts("");
	for(int i=0;i<5;i++){
		for(int j=0;j<5;j++)
			if(i==ex && j==ey)
				printf("*");
			else
				printf("%d",(b>>(i*5+j))&1);
		puts("") ;
	}
}

bool dfs(int b,int ex,int ey,int dep,int mxdep){
	//output(b,ex,ey);
    if(b==en && ex==2 && ey==2)
        return 1;
    if(dep+f(b,ex,ey)>mxdep)
        return 0;
    for(int i=0;i<8;i++){
        int xx=ex+d[i][0],yy=ey+d[i][1];
        if(xx<0 || xx>4 || yy<0 || yy>4)
            continue;
        int tmp=(b>>(xx*5+yy))&1;
        tmp=b|(tmp<<(ex*5+ey));
        tmp&=(1<<25)-1-(1<<(xx*5+yy));
        if(dfs(tmp,xx,yy,dep+1,mxdep))
        	return 1;
    }
    return 0;
}

int main(){
    scanf("%d",&t);
    while(t--){
        int num=0,ex,ey;
        for(int i=0;i<5;i++){
            scanf("%s",s[i]);
            for(int j=0;j<5;j++)
                if(s[i][j]=='*')
                    ex=i,ey=j;
                else if(s[i][j]=='1')
                    num+=(1<<(i*5+j));
        }
        int ans=0;
        while(ans<=15 && !dfs(num,ex,ey,0,ans))
            ans++;
        if(ans>15)
            puts("-1");
        else
            printf("%d\n",ans);
    }
    return 0;
}
